<template>
  <div class="home">
    <header class="header">
      <h1><i class="fas fa-apple-alt"></i> 水果腐烂检测系统</h1>
    </header>

    <main class="main-content">
      <div class="upload-section">
        <div class="upload-area" @click="selectImage">
          <input type="file" ref="fileInput" @change="handleFileSelect" accept="image/*" style="display: none;">
          <div v-if="!imageUrl" class="upload-placeholder">
            <i class="fas fa-cloud-upload-alt"></i>
            <p>点击上传图片或拖拽图片到此处</p>
          </div>
          <div v-else class="image-preview">
            <div class="detection-image-container">
              <img :src="imageUrl" alt="上传的图片" ref="detectionImage">
              <div
                v-if="detectionResult"
                class="detection-box"
                :style="getBoxStyle()">
                <div class="detection-label">
                  {{ detectionResult.fruitType }} - {{ detectionResult.freshness }}
                </div>
              </div>
            </div>
            <button @click="clearImage" class="clear-btn">
              <i class="fas fa-times"></i>
            </button>
          </div>
        </div>

        <div class="action-buttons">
          <button @click="detectFruit" :disabled="!imageUrl || isDetecting" class="detect-btn">
            <i class="fas fa-search"></i>
            {{ isDetecting ? '检测中...' : '开始检测' }}
          </button>
        </div>
      </div>

      <div class="result-section" v-if="detectionResult">
        <div class="result-card">
          <h3>检测结果</h3>
          <div class="result-content">
            <div class="result-item">
              <span>水果类型:</span>
              <span>{{ detectionResult.fruitType }}</span>
            </div>
            <div class="result-item">
              <span>新鲜度:</span>
              <span :class="detectionResult.freshness === 'fresh' ? 'fresh' : 'rotten'">
                {{ detectionResult.freshness === 'fresh' ? '新鲜' : '腐烂' }}
              </span>
            </div>
            <div class="result-item">
              <span>置信度:</span>
              <span>{{ (detectionResult.confidence * 100).toFixed(1) }}%</span>
            </div>
            <div class="result-item">
              <span>检测框坐标:</span>
              <span>X: {{ detectionResult.x }}, Y: {{ detectionResult.y }}, W: {{ detectionResult.width }}, H: {{ detectionResult.height }}</span>
            </div>
          </div>
        </div>
      </div>
    </main>
  </div>
</template>

<script>
export default {
  name: 'HomePage',
  data() {
    return {
      imageUrl: null,
      isDetecting: false
    }
  },
  computed: {
    detectionResult() {
      return this.$store.state.detectionResult
    }
  },
  methods: {
    selectImage() {
      this.$refs.fileInput.click()
    },
    handleFileSelect(event) {
      const file = event.target.files[0]
      if (file) {
        const reader = new FileReader()
        reader.onload = (e) => {
          this.$store.commit('setImageUrl', e.target.result)
          this.imageUrl = e.target.result
        }
        reader.readAsDataURL(file)
      }
    },
    clearImage() {
      this.imageUrl = null
      this.$store.commit('setImageUrl', null)
      this.$refs.fileInput.value = ''
    },
    async detectFruit() {
      if (this.imageUrl) {
        await this.$store.dispatch('detectFruit', this.imageUrl)
      }
    },
    getBoxStyle() {
      if (!this.detectionResult) return {}

      // 获取图片实际尺寸
      const img = this.$refs.detectionImage
      if (!img) return {}

      const imgWidth = img.naturalWidth || img.width
      const imgHeight = img.naturalHeight || img.height

      // 计算相对位置
      const scaleX = imgWidth / img.offsetWidth
      const scaleY = imgHeight / img.offsetHeight

      return {
        position: 'absolute',
        left: `${this.detectionResult.x / scaleX}px`,
        top: `${this.detectionResult.y / scaleY}px`,
        width: `${this.detectionResult.width / scaleX}px`,
        height: `${this.detectionResult.height / scaleY}px`,
        border: '2px solid #ff6b6b',
        backgroundColor: 'rgba(255, 107, 107, 0.1)',
        borderRadius: '4px'
      }
    }
  }
}
</script>

